def main() -> None:
    work_dir = Path("/kaggle/working") if Path("/kaggle/working").exists() else Path.cwd()
    payload = base64.b64decode("".join(CG_RUNTIME_B64.split()))
    with zipfile.ZipFile(BytesIO(payload)) as zf:
        zf.extractall(work_dir)
    cg_dir = work_dir / "cg"
    files = [str(path.relative_to(work_dir)) for path in sorted(cg_dir.rglob("*")) if path.is_file()]
    manifest = {
        "created_at_utc": datetime.now(timezone.utc).isoformat(),
        "runtime_dir": str(cg_dir),
        "files": files,
        "note": "Python cg runtime extracted for Pokemon TCG AI Battle downstream Kaggle kernels.",
    }
    (work_dir / "cg_runtime_manifest.json").write_text(json.dumps(manifest, indent=2) + "\n", encoding="utf-8")
    print(json.dumps(manifest, indent=2), flush=True)


if __name__ == "__main__":
    main()
